///|
test "grader accepts fresh complete identifiers" {
  assert_true(is_identifier("Z"))
  assert_true(is_identifier("value_42"))
  assert_true(is_identifier("__"))
}

///|
test "grader rejects surrounding and invalid text" {
  assert_false(is_identifier(""))
  assert_false(is_identifier("!name?"))
  assert_false(is_identifier("name!"))
  assert_false(is_identifier("x-y"))
  assert_false(is_identifier(" name "))
}
